/**
 * Generated by quail.
 *
 * Network-resilience baseline for https://gohugo.io/. Asserts the page
 * survives the failure modes a real user encounters on a poor
 * connection: throttled bandwidth, offline reload, and 429 rate-limit
 * responses. These are common production regressions that pass a
 * happy-path suite — adding them deterministically closes the gap.
 *
 * Filter: `npx playwright test --grep @kind:network`
 */
import { test, expect } from '@playwright/test'

test.describe.configure({ mode: 'parallel' })
test.describe('Gohugo — network resilience @ https://gohugo.io/', () => {
  test('@kind:network @slow-3g page renders under throttled bandwidth', async ({ page, context }) => {
    // Throttle every request by 1.5s before responding. Page must
    // still render the primary content (h1) within a generous budget.
    await context.route('**/*', async route => {
      await new Promise(r => setTimeout(r, 1500))
      await route.continue()
    })
    await page.goto('/', { timeout: 60_000 })
    await expect(page.locator('h1, [role="heading"][aria-level="1"]').first()).toBeVisible({ timeout: 30_000 })
  })

  test('@kind:network @offline-reload offline reload shows a sensible failure surface', async ({ page, context }) => {
    await page.goto('/')
    await context.setOffline(true)
    // The browser raises a navigation error; we capture it and assert
    // the page didn't silently double-render with stale content.
    let errored = false
    try {
      await page.reload({ timeout: 5000 })
    } catch {
      errored = true
    }
    expect.soft(errored, 'expected reload to fail when offline').toBe(true)
    await context.setOffline(false)
  })

  test('@kind:network @rate-limit 429 response is handled gracefully', async ({ page, context }) => {
    let calls = 0
    await context.route('**/*', async route => {
      calls++
      if (calls === 1) return route.continue() // allow the initial doc
      // Stub all subsequent fetches as 429 with a Retry-After.
      await route.fulfill({ status: 429, headers: { 'Retry-After': '1' }, body: 'rate limited' })
    })
    await page.goto('/', { waitUntil: 'domcontentloaded' })
    // Even with downstream 429s the initial document should render.
    await expect(page).toHaveURL(/.+/)
  })
})

